-- Weapon quality reference table, seeded from OggDude DataCustom/ItemDescriptors.xml

create table if not exists ref_weapon_qualities (
  key         text primary key,
  name        text not null,
  description text not null default '',
  is_ranked   boolean not null default false
);

alter table ref_weapon_qualities enable row level security;

create policy "anon read ref_weapon_qualities"
  on ref_weapon_qualities for select to anon using (true);

create policy "auth read ref_weapon_qualities"
  on ref_weapon_qualities for select to authenticated using (true);

on conflict (key) do update set
  name        = excluded.name,
  description = excluded.description,
  is_ranked   = excluded.is_ranked;
